#!/usr/bin/env python3
import hashlib, zlib, bz2, lzma, struct
from pathlib import Path

p=Path('/home/ctfplayer/ctf_files/chal/cell.pkg')
data=p.read_bytes()

# header-derived content id
cid=b''
if b'EP0001-CELL_00-' in data[:0x200]:
    i=data.find(b'EP0001-CELL_00-')
    cid=data[i:i+0x20].split(b'\x00')[0]
else:
    # best effort printable token around header
    hdr=data[:0x200]
    toks=[t for t in hdr.split(b'\x00') if len(t)>=8 and all(32<=c<127 for c in t)]
    cid=max(toks,key=len) if toks else b''

keys=[]
if cid:
    keys += [cid, cid.decode('latin1','ignore').encode()]
    m=hashlib.md5(cid).hexdigest().encode(); s=hashlib.sha1(cid).hexdigest().encode()
    mb=hashlib.md5(cid).digest(); sb=hashlib.sha1(cid).digest()
    keys += [m,s,mb,sb,m[:16],s[:16],mb[:8],sb[:8]]
    # substrings
    for src in [cid,m,s]:
        for L in [4,8,16]:
            if len(src)>=L:
                keys.append(src[:L]); keys.append(src[-L:])
# uniq
uniq=[]
seen=set()
for k in keys:
    if k and k not in seen:
        seen.add(k); uniq.append(k)
keys=uniq

sigs={
    b'\x7fELF':'ELF', b'MZ':'MZ', b'PK\x03\x04':'ZIP', b'\x1f\x8b':'GZIP',
    b'\xfd7zXZ\x00':'XZ', b'\x28\xb5\x2f\xfd':'ZSTD', b'BZh':'BZIP2', b'7z\xbc\xaf\x27\x1c':'7Z'
}

bitrev=bytes(int(f'{i:08b}'[::-1],2) for i in range(256))

def nibswap(b):
    return bytes(((x&0xf)<<4)|((x>>4)&0xf) for x in b)

def printable_ratio(b):
    if not b: return 0.0
    good=sum(1 for x in b if x in (9,10,13) or 32<=x<127)
    return good/len(b)

def xor_with_key(buf,key):
    kl=len(key)
    return bytes(buf[i]^key[i%kl] for i in range(len(buf)))

results=[]

transforms=[]
transforms.append(('raw', lambda b:b))
for k in range(256):
    transforms.append((f'xor_{k:02x}', lambda b,k=k: bytes(x^k for x in b)))
transforms += [
    ('nibswap', nibswap),
    ('bitrev', lambda b: bytes(bitrev[x] for x in b)),
    ('nibswap_xor_aa', lambda b: bytes((((x&0xf)<<4)|((x>>4)&0xf))^0xaa for x in b)),
    ('bitrev_xor_aa', lambda b: bytes(bitrev[x]^0xaa for x in b)),
]

# sliding window carve checks for signatures after transform
window=0x20000
step=0x1000
for tname,tfun in transforms:
    tdata=tfun(data)
    pr=printable_ratio(tdata[:0x4000])
    if pr>0.65:
        results.append((999,'printable',0,tname,f'printable ratio start={pr:.3f}'))
    # global signature search
    for s,name in sigs.items():
        pos=tdata.find(s)
        if pos!=-1:
            results.append((0,'sig',pos,tname,f'{name} at 0x{pos:x}'))
    # decompression attempts on windows for gzip/zlib/bz2/xz
    for off in range(0,len(tdata),step):
        chunk=tdata[off:off+window]
        if len(chunk)<64: break
        # quick prefilter
        for fn,label in [
            (lambda c: zlib.decompress(c), 'zlib'),
            (lambda c: bz2.decompress(c), 'bz2'),
            (lambda c: lzma.decompress(c), 'lzma/xz')
        ]:
            try:
                out=fn(chunk)
                if len(out)>256 and printable_ratio(out[:2048])>0.2:
                    rr=printable_ratio(out[:4096])
                    ev=f'{label} ok out={len(out)} pr={rr:.3f}'
                    results.append((1,'decomp',off,tname,ev))
            except Exception:
                pass

# trivial stream ciphers: repeating-xor with keys derived from cid/hash
for k in keys:
    dec=xor_with_key(data,k)
    pr=printable_ratio(dec[:0x4000])
    if pr>0.6:
        results.append((50,'keyprint',0,f'repxor[{k[:16]!r}]',f'pr={pr:.3f}'))
    for s,name in sigs.items():
        pos=dec.find(s)
        if pos!=-1:
            results.append((2,'keysig',pos,f'repxor[{k.hex()[:32]}]',f'{name} at 0x{pos:x}'))

# sort by priority then offset
results=sorted(results,key=lambda x:(x[0],x[2]))

print(f'content_id={cid!r}')
print(f'keys_tested={len(keys)}')
for r in results[:120]:
    print(r)

# extract promising blobs if any
# choose signature hits except at 0 for PKG magic false positive
cand=0
for pr,typ,off,tname,ev in results:
    if typ in ('sig','keysig') and off>0 and ('ELF' in ev or 'MZ' in ev or 'ZIP' in ev or 'GZIP' in ev or 'XZ' in ev or 'BZIP2' in ev or '7Z' in ev or 'ZSTD' in ev):
        if tname=='raw' and ev.startswith('ZIP at 0x1'): # skip pkg header
            continue
        # recreate bytes
        if tname.startswith('xor_'):
            k=int(tname.split('_')[1],16)
            tdata=bytes(x^k for x in data)
        elif tname=='nibswap': tdata=nibswap(data)
        elif tname=='bitrev': tdata=bytes(bitrev[x] for x in data)
        elif tname.startswith('repxor['):
            continue
        elif tname=='raw': tdata=data
        else:
            continue
        blob=tdata[off:off+0x58000]
        out=Path(f'/home/ctfplayer/ctf_files/chal/candidate_{cand}_{tname}_0x{off:x}.bin')
        out.write_bytes(blob)
        cand+=1
        if cand>=5: break
print(f'candidates_written={cand}')

